int findLargest(int a, int b, int c) {
    // Compare each pair of numbers to find the maximum
    if (a >= b && a >= c) {
        return a;
    } else if (b >= a && b >= c) {
        return b;
    } else {
        return c;
    }
}

int main() {
    // Input from user
    int num1, num2, num3;

    cout << "Enter three integers: ";
    cin >> num1 >> num2 >> num3;

    // Find the largest number
