```php
function isPrime($number) {
    // Check if the number is less than 2
    if ($number < 2) {
        return false;
    }

    // Check if the number is 2
    if ($number == 2) {
        return true;
    }

    // Check if the number is even
    if ($number % 2 == 0) {
        return false;
    }

    // Check divisibility from 3 to the square root of the number
    for ($i = 3; $i <= sqrt($number); $i += 2) {
        if ($number % $i == 0) {
            return false;
        }
    }

    return true;
}

// Example usage:
