```javascript
function flattenObject(obj) {
    let result = {};

    function recurse(cur, arrKey) {
        if (Array.isArray(cur)) {
            cur.forEach((item, index) => {
                recurse(item, `${arrKey}[${index}]`);
            });
        } else if (typeof cur === 'object' && cur !== null) {
            for (let k in cur) {
                if (cur.hasOwnProperty(k)) {
                    recurse(cur[k], `${arrKey}${arrKey ? '.' : ''}${k}`);
                }
            }
        } else {
            result[arrKey] = cur;
        }
    }

    recurse(obj, '');
    return result;
}

