    // Table header
    std::cout << "<tr><th>Name</th><th>Breed</th></tr>\n";

    // Iterate over the pandas vector and add rows to the table
    for (const auto& panda : pandas) {
        std::cout << "<tr><td>" << panda.name << "</td><td>" << panda.breed << "</td></tr>\n";
